try:
    from datamodel import TradingState
except ModuleNotFoundError:
    from prosperity4bt.datamodel import TradingState

# Products routed to blend_fair_ovr_submission instead of the super stack.
B = {"PEBBLES_XL", "PEBBLES_XS", "GALAXY_SOUNDS_SOLAR_WINDS", "SLEEP_POD_LAMB_WOOL",
     "OXYGEN_SHAKE_EVENING_BREATH", "MICROCHIP_CIRCLE", "OXYGEN_SHAKE_CHOCOLATE",
     "PANEL_1X2", "PANEL_4X4"}
BX = B | {"MICROCHIP_CIRCLE", "MICROCHIP_OVAL", "MICROCHIP_RECTANGLE",
          "MICROCHIP_SQUARE", "MICROCHIP_TRIANGLE"}


class Trader:
    def __init__(self):
        self.super = Hybrid_959_selective_router.Trader()
        self.blend = blend_fair_ovr_submission.Trader()

    def run(self, state):
        raw = state.traderData or ""
        try:
            d = json.loads(raw) if raw else {}
            d = d if isinstance(d, dict) else {}
        except Exception:
            d = {}

        state.traderData = d.get("super", "")
        so, _, sd = self.super.run(state)

        orig = state.order_depths
        state.order_depths = {p: v for p, v in orig.items() if p in BX}
        state.traderData = d.get("blend", "")
        try:
            bo, _, bd = self.blend.run(state)
        finally:
            state.order_depths = orig

        r = {p: o for p, o in so.items() if p not in B}
        for p in B:
            o = bo.get(p)
            if o:
                r[p] = o
            else:
                r.pop(p, None)
        return r, 0, json.dumps({"super": sd, "blend": bd}, separators=(",", ":"))